#!/usr/bin/env python3
from pathlib import Path
import argparse, json, shutil, html

AGIALPHA = "0xA61a3B3a130a9c20768EEBF97E21515A6046a1fA"
SITE_TITLE = "GoalOS AGIALPHA Ascension"
TAGLINE = "Proof-settled AI workflow work for sovereign institutions."

def esc(x): return html.escape(str(x), quote=True)

def write_page(out, name, title, body, active=""):
    out = Path(out); path = out / name; path.parent.mkdir(parents=True, exist_ok=True)
    links = [('index.html','Home'),('flagship-use-case.html','Flagship'),('proof-card-003.html','Proof Card 003'),('agialpha-ledger-route.html','AGIALPHA Route'),('sovereign-rsi-control-plane.html','Sovereign RSI'),('evidence-docket.html','Evidence'),('season-001.html','Season 001')]
    nav = "".join([f"<a class=\"{'active' if href==active else ''}\" href=\"{href}\">{label}</a>" for href,label in links])
    doc = f"""<!doctype html><html lang=\"en\"><head><meta charset=\"utf-8\"/><meta name=\"viewport\" content=\"width=device-width, initial-scale=1\"/><title>{esc(title)} - {SITE_TITLE}</title><link rel=\"stylesheet\" href=\"assets/goalos-flagship-v7.css\"/><meta name=\"description\" content=\"{esc(TAGLINE)}\"/></head><body><header class=\"topbar\"><a class=\"brand\" href=\"index.html\"><span class=\"crest\">G</span><span>{SITE_TITLE}</span></a><nav>{nav}</nav></header><main>{body}</main><footer><div><strong>{SITE_TITLE}</strong><br/>The intelligence stays private. The proof becomes verifiable.</div><div class=\"small\">Illustrative until live Evidence Docket completion. No investment, legal, tax, security, or mainnet authorization claim.</div></footer></body></html>"""
    path.write_text(doc, encoding='utf-8')

def hero(kicker, title, subtitle, chips=""):
    return f"<section class=\"hero\"><div class=\"kicker\">{kicker}</div><h1>{title}</h1><p class=\"lede\">{subtitle}</p><div class=\"chips\">{chips}</div></section>"

def card(title, text, cls=""):
    return f"<article class=\"card {cls}\"><h3>{title}</h3><p>{text}</p></article>"

def step(n, title, text, meta=""):
    return f"<article class=\"step\"><div class=\"stepnum\">{n}</div><div><h3>{title}</h3><p>{text}</p><code>{meta}</code></div></article>"

def table(headers, rows):
    th = ''.join(f'<th>{esc(h)}</th>' for h in headers)
    trs = ''.join('<tr>'+''.join(f'<td>{c}</td>' for c in r)+'</tr>' for r in rows)
    return f"<div class=\"tablewrap\"><table><thead><tr>{th}</tr></thead><tbody>{trs}</tbody></table></div>"

CSS = r'''
:root{--ink:#071227;--navy:#071227;--blue:#0f2a4e;--ivory:#f6f0e7;--paper:#fffaf1;--gold:#b98b2c;--gold2:#f0cf84;--line:#dfd1bd;--muted:#52627a;--shadow:0 24px 70px rgba(7,18,39,.14)}*{box-sizing:border-box}body{margin:0;background:linear-gradient(180deg,#faf5ec 0%,#fffaf1 42%,#f4ecdf 100%);color:var(--ink);font:16px/1.55 Inter,ui-sans-serif,system-ui,-apple-system,Segoe UI,Arial,sans-serif}.topbar{height:70px;background:#071227;color:white;display:flex;align-items:center;justify-content:space-between;padding:0 32px;position:sticky;top:0;z-index:10;box-shadow:0 10px 30px rgba(0,0,0,.15)}.brand{color:white;text-decoration:none;font-weight:900;letter-spacing:.01em;display:flex;align-items:center;gap:12px}.crest{display:inline-grid;place-items:center;width:34px;height:34px;border:1px solid rgba(240,207,132,.6);border-radius:50%;color:var(--gold2)}nav{display:flex;gap:18px;flex-wrap:wrap;justify-content:flex-end}nav a{color:#dbe6fb;text-decoration:none;font-size:13px;font-weight:800;opacity:.9}nav a.active,nav a:hover{color:#f7d98f}main{max-width:1220px;margin:auto;padding:64px 28px 80px}.hero{padding:58px 0 38px;border-bottom:1px solid var(--line)}.kicker{text-transform:uppercase;color:var(--gold);font-weight:950;letter-spacing:.22em;font-size:12px}.hero h1{font-size:clamp(42px,6vw,82px);line-height:.96;letter-spacing:-.055em;margin:16px 0 22px;max-width:1050px}.lede{font-size:clamp(18px,2vw,24px);max-width:940px;color:#2c3a50}.chips{display:flex;gap:10px;flex-wrap:wrap;margin-top:24px}.chip{background:#fff;border:1px solid var(--line);border-radius:999px;padding:9px 13px;font-weight:850;color:#24324a}.section{padding:56px 0;border-bottom:1px solid var(--line)}.section h2{font-size:clamp(30px,4vw,50px);letter-spacing:-.04em;margin:0 0 14px}.section .intro{font-size:18px;color:#43506a;max-width:850px}.grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px;margin-top:26px}.grid2{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:20px;margin-top:26px}.card{background:rgba(255,255,255,.84);border:1px solid var(--line);border-radius:24px;padding:26px;box-shadow:var(--shadow);min-height:160px}.card.dark{background:#071227;color:white;border-color:#1f385e}.card.gold{background:linear-gradient(135deg,#fff6d7,#fffaf1);border-color:#e8c76a}.card h3{font-size:22px;margin:0 0 10px;letter-spacing:-.02em}.card p{margin:0;color:inherit}.route{display:grid;gap:13px;margin-top:28px}.step{display:grid;grid-template-columns:58px 1fr;gap:18px;align-items:start;background:#fff;border:1px solid var(--line);border-radius:22px;padding:20px;box-shadow:0 12px 36px rgba(7,18,39,.08)}.stepnum{width:42px;height:42px;border-radius:50%;display:grid;place-items:center;background:#071227;color:#f0cf84;font-weight:1000}.step h3{margin:0 0 6px;font-size:20px}.step p{margin:0 0 10px;color:#3a4963}.step code{display:inline-block;white-space:normal;background:#f4ede0;border:1px solid #e0d0bb;padding:7px 9px;border-radius:10px;color:#26344b}.panel{background:#071227;color:white;border-radius:34px;padding:34px;margin-top:28px;box-shadow:var(--shadow);position:relative;overflow:hidden}.panel:before{content:"";position:absolute;inset:0;background:radial-gradient(circle at 85% 10%,rgba(240,207,132,.22),transparent 35%);pointer-events:none}.panel>*{position:relative}.panel h2,.panel h3{color:white}.panel p{color:#dbe6fb}.tablewrap{overflow:auto;border:1px solid var(--line);border-radius:24px;background:white;box-shadow:var(--shadow);margin-top:24px}table{border-collapse:collapse;width:100%;min-width:760px}th,td{text-align:left;padding:16px;border-bottom:1px solid #eadfce;vertical-align:top}th{background:#071227;color:#f6e5b0;font-size:12px;text-transform:uppercase;letter-spacing:.12em}td{color:#24324a}.quote{font-size:28px;line-height:1.15;letter-spacing:-.03em;font-weight:950;background:#fff;border-left:8px solid var(--gold);padding:26px;border-radius:20px;margin:26px 0}.warning{background:#fff9e8;border:1px solid #ead7a2;border-radius:20px;padding:18px;color:#4b3b1d}.footercta{display:flex;gap:16px;flex-wrap:wrap;margin-top:24px}.btn{display:inline-flex;align-items:center;justify-content:center;padding:13px 18px;border-radius:999px;font-weight:950;text-decoration:none;background:#071227;color:white;border:1px solid #071227}.btn.alt{background:white;color:#071227}.small{font-size:13px;color:#697790}footer{border-top:1px solid var(--line);padding:34px 28px;background:#fffaf1;display:flex;justify-content:space-between;gap:24px}.rsi{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-top:28px}.rsi div{background:white;border:1px solid var(--line);border-radius:20px;padding:18px;min-height:128px}.rsi strong{display:block;color:#b98b2c;text-transform:uppercase;font-size:12px;letter-spacing:.14em;margin-bottom:8px}@media(max-width:900px){.grid,.grid2,.rsi{grid-template-columns:1fr}nav{display:none}.hero h1{font-size:42px}main{padding:42px 18px}.topbar{padding:0 18px}footer{display:block}.step{grid-template-columns:1fr}.stepnum{margin-bottom:6px}}
'''

def build(out='site'):
    out = Path(out)
    if not out.exists():
        out.mkdir(parents=True)
