    flagship += card('After','The buyer sees what was tested, who reviewed it, which proof exists, what remains private, and what can safely improve the next workflow.','gold')
    flagship += '</div></section><section class="section"><h2>What becomes reusable through RSI</h2><p class="intro">The accepted artifact is not just a report. It becomes a scoped institutional upgrade: a reusable procurement evidence template that can improve future sponsor, buyer, and enterprise trust workflows.</p><div class="rsi"><div><strong>Observe</strong>Buyer trust questions expose missing evidence.</div><div><strong>Improve</strong>Builder creates a stronger procurement artifact.</div><div><strong>Prove</strong>Reviewer validates evidence and claim boundaries.</div><div><strong>Evolve</strong>Selection Gate grants scoped upgrade rights.</div></div></section>'
    flagship += '<section class="section"><h2>Public-safe output</h2>' + table(['Artifact','Purpose','Public / private boundary'], [['Proof Card 003','Public-safe narrative showing what improved and what was validated.','Public'],['Evidence Docket','Structured evidence map for audit and replay.','Public summary; private evidence off-chain'],['Credential','Records who completed approved proof work.','Public-safe'],['Reputation update','Improves routing for future missions.','Public-safe score or event'],['RSI artifact','Reusable procurement template only after Selection Gate approval.','Scoped; rollback-ready']]) + '<div class="footercta"><a class="btn" href="proof-card-003.html">Read Proof Card 003</a><a class="btn alt" href="sovereign-rsi-control-plane.html">See the RSI loop</a></div></section>'
    write_page(out,'flagship-use-case.html','Sovereign AI Procurement Control Tower',flagship,'flagship-use-case.html')
    pc3 = hero('Public proof card','Proof Card 003 - Sovereign AI Procurement Control Tower','Illustrative proof card for a procurement trust workflow. It shows the intended public artifact before the live Evidence Docket is completed.')
    pc3 += '<section class="section"><h2>What this proof card says</h2><div class="grid2">' + card('The claim','A procurement trust workflow can be converted into a proof mission with reviewer validation and a public-safe evidence trail.','gold') + card('The boundary','This is illustrative until live Evidence Docket completion. It is not a mainnet deployment, investment, legal, tax, or security claim.') + card('The upgrade','Accepted procurement evidence artifacts may improve future buyer-trust workflows only after Selection Gate approval.') + card('The buyer value','Buyers get a clearer path to evaluate, trust, audit, and govern AI workflow adoption.') + '</div></section><section class="section"><h2>Proof path</h2><div class="route">'
