    ledger += '</div></section><section class="section"><h2>Contract route</h2><div class="route">'
    route=['AEPGoalOSCommitRegistry','AEPRunCommitmentRegistry','JobRegistry','JobClaimBondManager','ProofSubmissionRegistry','ReviewerBondRegistry','ProofCardRegistry','ProofCredentialRegistry','ReputationRegistry','AEPEvidenceDocketRegistry','AEPSelectionGate','AEPChronicleRegistry']
    desc=['Defines the mission and success boundary.','Commits the run plan and artifact versions.','Posts proof mission and AGIALPHA reward.','Records builder claim and bond.','Records proof hash, URI, and proof bond.','Records reviewer bond, review, and challenge window.','Registers public-safe Proof Card.','Issues proof credential.','Records approved proof reputation.','Anchors Evidence Docket.','Issues or denies upgrade rights.','Records durable institutional memory.']
    for i,(r,d) in enumerate(zip(route,desc),1): ledger += step(i,r,d,r)
    ledger += '</div></section>'
