    rsi = hero('Sovereign RSI','Sovereign RSI through proof-backed upgrade rights','The system improves efficiently by reusing only artifacts that survived evidence, evaluation, reviewer validation, scope control, challenge window, monitoring, and rollback readiness.')
    rsi += '<section class="section"><h2>The RSI control plane</h2><p class="intro">The system does not let any output automatically change future work. It gives artifacts the right to influence future work only after proof.</p><div class="rsi"><div><strong>1. Commit</strong>GoalOS defines aim, scope, risk, evidence and rollback obligations.</div><div><strong>2. Execute</strong>Builders and agents perform the workflow under bounded authority.</div><div><strong>3. Prove</strong>ProofBundle and Evidence Docket record what happened.</div><div><strong>4. Review</strong>Reviewer validates evidence under bond, rubric, and challenge window.</div><div><strong>5. Select</strong>Selection Gate grants or denies scoped upgrade rights.</div><div><strong>6. Propagate</strong>Only accepted artifacts improve routing, templates, and future runs.</div><div><strong>7. Monitor</strong>Canary usage checks drift, failures, and unintended effects.</div><div><strong>8. Roll back</strong>Unsafe artifacts can be demoted, reverted, and chronicled.</div></div></section>'
    rsi += '<section class="section"><h2>Why this is efficient</h2><div class="grid2">' + card('It compounds what worked','Validated artifacts can be reused across future procurement, sponsor, and trust workflows.','gold') + card('It rejects what failed','Unproven or unsafe artifacts do not receive upgrade rights and cannot shape production routing.') + card('It preserves sovereignty','The institution controls evidence, claims, scope, review, rollout, and rollback.') + card('It makes learning auditable','Improvement is recorded as evidence, not memory mythology.') + '</div></section>'
    write_page(out,'sovereign-rsi-control-plane.html','Sovereign RSI Control Plane',rsi,'sovereign-rsi-control-plane.html')
    evidence = hero('Evidence Docket','The proof room behind every claim','An Evidence Docket is the structured record that lets a buyer, sponsor, reviewer, or auditor see what happened without exposing private intelligence.')
    evidence += '<section class="section"><h2>Evidence Docket sections</h2>' + table(['Section','What it proves','Example'], [['Commitment','What the mission was allowed to do.','GoalOSCommit'],['Execution','What was run and under which constraints.','RunCommitment'],['Proof','What evidence was produced.','ProofBundle'],['Review','Who reviewed it and by what rubric.','EvalAttestation'],['Selection','Whether it earned upgrade rights.','SelectionCertificate'],['Rollout','Where accepted artifacts may be used.','RolloutReceipt'],['Rollback','How unsafe changes can be reversed.','RollbackReceipt'],['Chronicle','Durable institutional memory.','AEPChronicleRegistry']]) + '<div class="warning">Private prompts, buyer data, internal files, legal documents, and sensitive evidence remain off-chain. Public pages show only public-safe proof anchors and summaries.</div></section>'
    write_page(out,'evidence-docket.html','Evidence Docket',evidence,'evidence-docket.html')
    season = hero('Season 001','Proof missions that create demand','The best launch sequence starts with understandable proof, then moves toward sovereign and enterprise trust.')
    season += '<section class="section"><h2>Recommended mission order</h2>' + table(['Mission','Buyer / sponsor value','Proof output'], [['Proof Card 001 - Buyer Rescue Workflow','Shows a simple support workflow improvement.','Buyer-safe Proof Card'],['Proof Card 002 - Procurement Trust Room','Shows evidence packaging for due diligence.','Trust Room Proof Card'],['Proof Card 003 - Procurement Control Tower','Shows a full governance, evidence, credential, and RSI loop.','Flagship Evidence Docket'],['Claims-Safe Launch Content','Reduces public messaging risk.','Reviewed claims card'],['Builder / Reviewer Quality','Improves the proof economy itself.','Reviewer rubric and reputation updates']]) + '</section>'
    write_page(out,'season-001.html','Season 001 Proof Missions',season,'season-001.html')
